import React, { useState } from 'react';

interface InputSectionProps {
  onSubmit: (situation: string) => void;
  isLoading: boolean;
}

const InputSection: React.FC<InputSectionProps> = ({ onSubmit, isLoading }) => {
  const [situation, setSituation] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (situation.trim()) {
      onSubmit(situation);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full space-y-4">
      <div className="relative group">
        <div className="absolute -inset-0.5 bg-gradient-to-r from-align-accent to-align-hover rounded-xl blur opacity-20 group-hover:opacity-40 transition duration-500"></div>
        <div className="relative">
          <textarea
            value={situation}
            onChange={(e) => setSituation(e.target.value)}
            placeholder="Describe the workplace situation... (e.g., 'I lost my train of thought in a meeting due to brain fog')"
            className="w-full h-32 md:h-40 bg-align-card border border-align-accent/30 rounded-xl p-4 text-align-text placeholder-align-text/30 focus:outline-none focus:border-align-accent focus:ring-1 focus:ring-align-accent transition-all resize-none text-base leading-relaxed"
            disabled={isLoading}
          />
        </div>
      </div>

      <div className="flex justify-end">
        <button
          type="submit"
          disabled={!situation.trim() || isLoading}
          className={`
            px-8 py-3 rounded-full font-semibold text-white tracking-wide transition-all duration-300 transform
            ${!situation.trim() || isLoading 
              ? 'bg-align-card text-align-text/30 cursor-not-allowed' 
              : 'bg-align-accent hover:bg-align-hover shadow-lg hover:shadow-align-accent/20 hover:-translate-y-0.5 active:translate-y-0'}
          `}
        >
          {isLoading ? (
            <span className="flex items-center gap-2">
              <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Aligning...
            </span>
          ) : (
            'Generate My Script'
          )}
        </button>
      </div>
    </form>
  );
};

export default InputSection;

import React, { useState } from 'react';
import { ScriptOption } from '../types';

interface ScriptCardProps {
  script: ScriptOption;
}

const ScriptCard: React.FC<ScriptCardProps> = ({ script }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(script.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-align-card/50 border border-align-accent/20 rounded-lg p-5 hover:border-align-accent/40 transition-colors">
      <div className="flex justify-between items-center mb-3">
        <span className="text-xs font-bold uppercase tracking-wider text-align-accent bg-align-dark/50 px-3 py-1 rounded-full border border-align-accent/10">
          {script.type}
        </span>
        <button
          onClick={handleCopy}
          className="text-align-text/50 hover:text-white transition-colors text-xs flex items-center gap-1.5"
          title="Copy to clipboard"
        >
          {copied ? (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
              Copied
            </>
          ) : (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
              Copy
            </>
          )}
        </button>
      </div>
      <div className="font-mono text-sm leading-relaxed text-align-text/90 whitespace-pre-wrap bg-align-dark/30 p-4 rounded border border-white/5">
        {script.content}
      </div>
    </div>
  );
};

export default ScriptCard;

